exercises.solution_code:
#include <iostream>
#include <random>

int main()
{
    unsigned int seed{};
    int n{};
    std::cin >> seed >> n;

    // First engine
    std::mt19937 mt1{ seed };
    std::uniform_int_distribution<int> dist1{ 1, 1000 };
    int sum1{ 0 };
    for (int i{ 0 }; i < n; ++i)
        sum1 += dist1(mt1);

    // Second engine, same seed
    std::mt19937 mt2{ seed };
    std::uniform_int_distribution<int> dist2{ 1, 1000 };
    int sum2{ 0 };
    for (int i{ 0 }; i < n; ++i)
        sum2 += dist2(mt2);

    std::cout << "Sum 1: " << sum1 << '\n';
    std::cout << "Sum 2: " << sum2 << '\n';
    if (sum1 == sum2)
        std::cout << "Match: yes\n";
    else
        std::cout << "Match: no\n";

    return 0;
}

