#include <iostream>
#include <random>

int main()
{
    int lo{}, hi{}, n{};
    std::cin >> lo >> hi >> n;

    std::mt19937 mt{ std::random_device{}() };
    std::uniform_int_distribution<int> dist{ lo, hi };

    int minVal{ hi + 1 };
    int maxVal{ lo - 1 };
    bool allValid{ true };

    for (int i{ 0 }; i < n; ++i) {
        int val{ dist(mt) };
        if (val < minVal) minVal = val;
        if (val > maxVal) maxVal = val;
        if (val < lo || val > hi)
            allValid = false;
    }

    std::cout << "Min: " << minVal << '\n';
    std::cout << "Max: " << maxVal << '\n';
    if (allValid)
        std::cout << "All valid: yes\n";
    else
        std::cout << "All valid: no\n";

    return 0;
}
